/****
 * Get CQP_TOTAL_CLAIMS_COMBINED from CQP_SUMMARY_CLAIMS
 * matching the current row period
 * By Adriana Centellas
 ****/

// Current row period
const currentPeriod = this.period;

// Get claims array safely
const claims = Array.isArray(this._parent.CQP_SUMMARY_CLAIMS)
  ? this._parent.CQP_SUMMARY_CLAIMS
  : [];

// Find the claim row with the same period
const match = claims.find(function(claim) {
  // Use Number() in case period comes as string
  return Number(claim.period) === Number(currentPeriod);
});

// If found, return the combined claims, otherwise null (or 0)
return match ? match.CQP_TOTAL_CLAIMS_COMBINED : 0;

/******
 * '=CQP_GWP_USD-(CQP_GWP_USD*(CQP_BROKERAGE_COMISSION+CQP_TAX))
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_GWP_USD) - (safeNumber(this.CQP_GWP_USD) * ((safeNumber(this.CQP_BROKERAGE_COMISSION)/100) + (safeNumber(this.CQP_TAX)/100)));

/*******
 * =CQP_CLAIM_USD/CQP_GWP_USD
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}
return safeNumber((safeNumber(this.CQP_CLAIM_USD) / safeNumber(this.CQP_GWP_USD)) * 100);

/******
 * '=CQP_BROKERAGE_COMISSION + CQP_TAX + CQP_LOSS_RADIO + CQP_UNDERWRITING_EXPENSES
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_BROKERAGE_COMISSION) + safeNumber(this.CQP_TAX) + safeNumber(this.CQP_LOSS_RADIO) + safeNumber(this.CQP_UNDERWRITING_EXPENSES);
